mapper.select:
select substr(add_time,1,10) as day, count(*) as newUsers from litemall_user where deleted = 0
and substr(add_time,1,10) >= #{startDate}
and substr(add_time,1,10) <= #{endDate}
group by substr(add_time,1,10) order by day

select substr(last_login_time,1,10) as day, count(distinct id) as dau from litemall_user where deleted = 0 and last_login_time is not null
and substr(last_login_time,1,10) >= #{startDate}
and substr(last_login_time,1,10) <= #{endDate}
group by substr(last_login_time,1,10) order by day

SELECT event_type AS eventType, COUNT(*) AS count FROM litemall_tracker_event WHERE deleted = 0
AND DATE(server_time) >= #{startDate}
AND DATE(server_time) <= #{endDate}
GROUP BY event_type ORDER BY count DESC

SELECT DATE(server_time) AS day, SUM(CASE WHEN event_type = 'page_view' THEN 1 ELSE 0 END) AS page_view, SUM(CASE WHEN event_type = 'goods_view' THEN 1 ELSE 0 END) AS goods_view, SUM(CASE WHEN event_type = 'add_cart' THEN 1 ELSE 0 END) AS add_cart, SUM(CASE WHEN event_type = 'order_create' THEN 1 ELSE 0 END) AS order_create, SUM(CASE WHEN event_type = 'order_pay' THEN 1 ELSE 0 END) AS order_pay FROM litemall_tracker_event WHERE deleted = 0
AND DATE(server_time) >= #{startDate}
AND DATE(server_time) <= #{endDate}
GROUP BY DATE(server_time) ORDER BY day

SELECT
    page_route AS pageRoute,
    COUNT(*) AS count,
    COUNT(DISTINCT user_id) AS uniqueUsers
FROM litemall_tracker_event
WHERE deleted = 0
AND event_type = #{eventType}

    AND DATE(server_time) >= #{startDate}


    AND DATE(server_time) <= #{endDate}

GROUP BY page_route
ORDER BY count DESC
LIMIT #{limit}
